/// <summary>
/// This class is an extension of SalesCreateOrder form and SalesTable datasource.
/// </summary>
[ExtensionOf(formDataSourceStr(SalesCreateOrder, SalesTable))]
internal final class ETGSalesCreateOrder_Extension
{
}

Method.Source:
/// <summary>
/// contains the logic for making business segment field as mandatory.
/// </summary>
/// <returns>int</returns>
int active()
{
    int ret =  next active();

    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        // Check if the current legal entity is NOT 'o018'
        if (curExt() != 'o018' &&  curExt() != 'o025')
        {
            this.object(fieldNum(SalesTable, ETGBusinessSegment)).mandatory(true);
        }
        else
        {
            // If the company is 'o018', ensure mandatory is false
            this.object(fieldNum(SalesTable, ETGBusinessSegment)).mandatory(false);
        }
    }
    else
    {
        this.object(fieldNum(SalesTable, ETGBusinessSegment)).visible(false);
        this.object(fieldNum(SalesTable, ETGBusinessSegment)).mandatory(false);
    }
    return ret;
}
